<script setup lang="ts">
import type { DatePickerInstance } from "@vuepic/vue-datepicker";
import VueDatePicker from "@vuepic/vue-datepicker";
import "@vuepic/vue-datepicker/dist/main.css";
import { format, isAfter, isSameDay, set } from "date-fns";
import { toast } from "vue3-toastify";

import Button from "../Button/index.vue";
import OutlinedButton from "../OutlinedButton/index.vue";
import SpinnerNumberInput from "../SpinnerNumberInput/index.vue";

const props = defineProps({
  modelValue: {
    type: Array as () => Date[],
    default: [],
  },
  id: {
    type: String,
    default: "",
  },
  label: {
    type: String,
    default: "",
  },
  placeholder: {
    type: String,
    default: "",
  },
  required: {
    type: Boolean,
    default: false,
  },
  disabled: {
    type: Boolean,
    default: false,
  },
  rangeTimePicker: {
    type: Boolean,
    default: true,
  },
  minDate: {
    type: [Date, Object as () => null],
    default: null,
  },
  maxDate: {
    type: [Date, Object as () => null],
    default: null,
  },
  isAllowSameDay: {
    type: Boolean,
    default: true,
  },
  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
});

const now = ref(new Date());

const selectedDate = ref<Date[]>([]);
const selectedTime = ref<{ hours: number[]; minutes: number[] }>({
  hours: [now.value.getHours(), now.value.getHours()],
  minutes: [now.value.getMinutes(), now.value.getMinutes()],
});

const datePicker = ref<DatePickerInstance | null>(null);

const emit = defineEmits(["update:modelValue"]);

const isValidDateTime = computed(() => {
  if (selectedDate.value.length < 2) return false;
  if (!props.rangeTimePicker) return true;

  try {
    // TODO: optimize logic in validating hour & minutes
    const minDate = props.minDate ?? new Date();
    const minTime = {
      hours: minDate.getHours(),
      minutes: minDate.getMinutes(),
    };

    const pickupDate = selectedDate.value[0];
    const dropOffDate = selectedDate.value[1];

    const pickupTime = {
      hours: selectedTime.value.hours[0],
      minutes: selectedTime.value.minutes[0],
    };
    const dropOffTime = {
      hours: selectedTime.value.hours[1],
      minutes: selectedTime.value.minutes[1],
    };

    const isSameAsMin = {
      pickup: isSameDay(pickupDate, minDate),
      dropOff: isSameDay(dropOffDate, minDate),
    };

    const isSamePickupDroOff = isSameDay(pickupDate, dropOffDate);

    const isValid = {
      hour:
        (!(!props.minDate && !props.maxDate)
          ? isSameAsMin.pickup
            ? pickupTime.hours >= minTime.hours
            : true
          : true) &&
        (!(!props.minDate && !props.maxDate)
          ? isSameAsMin.dropOff
            ? dropOffTime.hours >= minTime.hours
            : true
          : true) &&
        (isSamePickupDroOff ? pickupTime.hours <= dropOffTime.hours : true),
      minute:
        (!(!props.minDate && !props.maxDate)
          ? isSameAsMin.pickup && pickupTime.hours === minTime.hours
            ? pickupTime.minutes >= minTime.minutes
            : true
          : true) &&
        (!(!props.minDate && !props.maxDate)
          ? isSameAsMin.dropOff && dropOffTime.hours === minTime.hours
            ? dropOffTime.minutes > minTime.minutes
            : true
          : true) &&
        (isSamePickupDroOff && pickupTime.hours === dropOffTime.hours
          ? pickupTime.minutes < dropOffTime.minutes
          : true),
    };

    return isValid.hour && isValid.minute;
  } catch (_) {
    return false;
  }
});

function onClickOpen() {
  const isFilled = props.modelValue.length > 0;

  const initialHours = isFilled
    ? [props.modelValue[0].getHours(), props.modelValue[1].getHours()]
    : [now.value.getHours(), now.value.getHours()];

  const initialMinutes = isFilled
    ? [props.modelValue[1].getMinutes(), props.modelValue[1].getMinutes()]
    : [now.value.getMinutes(), now.value.getMinutes()];

  selectedTime.value = {
    hours: [...initialHours],
    minutes: [...initialMinutes],
  };
}

function onSelectDate(value: Date) {
  if (selectedDate.value.length === 0) {
    selectedDate.value.push(value);
    return;
  }

  isAfter(new Date(value), selectedDate.value[0])
    ? selectedDate.value.push(value)
    : selectedDate.value.unshift(value);
}

function onSelectRangeStart(value: Date) {
  selectedDate.value = [];
  onSelectDate(value);
}

function onSelectRangeEnd(value: Date) {
  onSelectDate(value);
  if (props.rangeTimePicker) datePicker?.value?.switchView("time");
}

function onClickConfirm(selectDate: () => void) {
  const startDate = new Date(selectedDate.value[0]);
  const finishDate = new Date(selectedDate.value[1]);

  if (!props.isAllowSameDay && isSameDay(startDate, finishDate)) {
    toast.error("Date can't be selected on the same day.");
    return;
  }

  selectDate();
}

function updateModelValue(date: Date[]) {
  try {
    const startDate = props.rangeTimePicker
      ? new Date(date[0])
      : set(new Date(date[0]), { hours: 0, minutes: 0, seconds: 0 });
    const endDate = props.rangeTimePicker
      ? new Date(date[1])
      : set(new Date(date[1]), { hours: 23, minutes: 59, seconds: 59 });

    selectedDate.value = [startDate, endDate];

    emit("update:modelValue", [startDate, endDate]);
  } catch (_) {
    emit("update:modelValue", []);
  }
}

const formatDate = (date: Date[] | null) => {
  if (!date) return "";

  const formatDateTime = `dd/MM/yyyy${props.rangeTimePicker ? ", HH:mm" : ""}`;

  return `${format(date[0], formatDateTime)} - ${format(date[1], formatDateTime)}`;
};

const pickerClass = computed(() => `custom-date-picker date-picker-${props.color}`);
</script>

<template>
  <div class="flex flex-col items-start text-sm font-[600] text-gray-700">
    <label
      v-if="props.label"
      :for="id"
      class="mb-1.5 text-sm font-[600] text-gray-700"
      @click="datePicker?.openMenu()"
    >
      {{ props.label }}
      <span v-if="props.required" class="text-primary-500">*</span>
    </label>
    <vue-date-picker
      range
      disable-time-range-validation
      ref="datePicker"
      :id="props.id"
      :min-date="props.minDate"
      :max-date="props.maxDate"
      :min-time="{ hours: 0, minutes: 0, seconds: 0 }"
      :max-time="{ hours: 23, minutes: 59, seconds: 59 }"
      :disabled="props.disabled"
      :model-value="props.modelValue as Date[]"
      :placeholder="props.placeholder as string"
      :format="formatDate"
      input-class-name="!py-2 !rounded-lg focus:!ring-primary-500"
      calendar-cell-class-name="!rounded-full"
       :class="pickerClass"
      @open="onClickOpen"
      @range-start="onSelectRangeStart($event)"
      @range-end="onSelectRangeEnd($event)"
      @update:model-value="updateModelValue($event)"
      :enable-time-picker="props.rangeTimePicker"
    >
      <template #time-picker-overlay="{ hours, minutes, setHours, setMinutes }">
        <div class="py-5 px-8 space-y-5">
          <div class="flex flex-col items-center">
            <p class="font-medium mb-2 text-center">Pick Up</p>
            <p class="font-medium mb-2 text-center">
              {{
                selectedDate.length > 1
                  ? format(selectedDate[0], "dd-MM-yyyy")
                  : "DD-MM-YYYY"
              }}
            </p>
            <div class="flex items-center space-x-3 w-3/4">
              <SpinnerNumberInput
                v-model="selectedTime.hours[0]"
                id="inputPickupHour"
                :min="0"
                :max="23"
                @update:model-value="
                  (event) => {
                    selectedTime.hours[0] = event;
                    setHours([...selectedTime.hours]);
                  }
                "
              />
              <span class="text-xl">:</span>
              <SpinnerNumberInput
                v-model="selectedTime.minutes[0]"
                id="inputPickupMinute"
                :min="0"
                :max="59"
                @update:model-value="
                  (event) => {
                    selectedTime.minutes[0] = event;
                    setMinutes([...selectedTime.minutes]);
                  }
                "
              />
            </div>
          </div>
          <hr />
          <div class="flex flex-col items-center">
            <p class="font-medium mb-2 text-center">Drop Off</p>
            <p class="font-medium mb-2 text-center">
              {{
                selectedDate.length > 1
                  ? format(selectedDate[1], "dd-MM-yyyy")
                  : "DD-MM-YYYY"
              }}
            </p>
            <div class="flex items-center space-x-3 w-3/4">
              <SpinnerNumberInput
                v-model="selectedTime.hours[1]"
                id="inputDropOffHour"
                :min="0"
                :max="23"
                @update:model-value="
                  (event) => {
                    selectedTime.hours[1] = event;
                    setHours([...selectedTime.hours]);
                  }
                "
              />
              <span class="text-xl">:</span>
              <SpinnerNumberInput
                v-model="selectedTime.minutes[1]"
                id="inputDropOffMinute"
                :min="0"
                :max="59"
                @update:model-value="
                  (event) => {
                    selectedTime.minutes[1] = event;
                    setMinutes([...selectedTime.minutes]);
                  }
                "
              />
            </div>
          </div>
        </div>
      </template>
      <template #action-row="{ modelValue, selectDate }">
        <div class="!w-full flex space-x-3">
          <OutlinedButton
            label="Cancel"
            class="w-full"
            :color="color"
            @on-click="datePicker?.closeMenu()"
          />
          <Button
            label="Confirm"
            class="w-full"
              :color="color"
            :disabled="!isValidDateTime"
            @on-click="onClickConfirm(selectDate)"
          />
        </div>
      </template>
    </vue-date-picker>
  </div>
</template>

<style scoped>
.custom-date-picker :deep(input) {
  font-weight: 400;
}

.custom-date-picker :deep(.dp__month_year_row) {
  font-weight: 400;
}

.custom-date-picker :deep(.dp__calendar_header) {
  font-weight: 500 !important;
}

.custom-date-picker :deep(.dp__calendar) {
  font-weight: 400 !important;
}

.custom-date-picker :deep(.dp__theme_light) {
  --dp-text-color: #344054;
}

.date-picker-primary :deep(.dp__theme_light) {
  --dp-primary-color: #F14848;
  --dp-range-between-dates-background-color: #FFF5F5;
}
.date-picker-success :deep(.dp__theme_light) {
  --dp-primary-color: #12B76A;
  --dp-range-between-dates-background-color: #ECFDF3;
}
.date-picker-info :deep(.dp__theme_light) {
  --dp-primary-color: #0BA5EC;
  --dp-range-between-dates-background-color: #F0F9FF;
